/**
 * Bundled demo media assets, embedded as base64 so the store can encrypt them
 * synchronously at construction (no asset-import machinery; identical behavior
 * in Vite, Vitest, and Node). The store wraps the raw bytes with the message
 * content key and serves the ciphertext at a `data:` URL, so the real
 * `useDecryptedMedia` path decrypts genuine ciphertext.
 *
 * Sources (no attribution required, embedded only for provenance):
 *   - Image: "Celestial Jellyfish" by W.carter, Wikimedia Commons, CC0 / public
 *     domain. Downscaled to 1024px and re-encoded as JPEG.
 *   - Video: "Going through a space tunnel with fractal shapes", Mixkit Free
 *     License (commercial use, no attribution). Trimmed to 5s, 480x270 H.264.
 *
 * Generated data — do not hand-edit the base64. The chunks are joined at runtime
 * (a flat array, not a `+` chain, so large assets don't overflow the parser).
 */
/* eslint-disable no-secrets/no-secrets -- base64-encoded media bytes, not credentials */
import { fromBase64 } from '@hushbox/shared';

export interface DemoAsset {
  readonly bytes: Uint8Array;
  readonly mimeType: string;
  readonly width: number;
  readonly height: number;
  /** Playback duration in ms (video assets only). */
  readonly durationMs?: number;
}

